const debug = logger('quill:toolbar');

type Handler = (this: Toolbar, value: any) => void;

interface ToolbarGroup {
  container: HTMLElement;
  toolbars: Set<Toolbar>;
  active: Toolbar | null;
  attached: WeakSet<HTMLElement>;
  observer: MutationObserver;
  documentObserver: MutationObserver;
  refresh: () => void;
}

const groups = new WeakMap<HTMLElement, ToolbarGroup>();

function isLive(toolbar: Toolbar) {
  return toolbar.quill.root.isConnected;
}

function getGroup(container: HTMLElement) {
  let group = groups.get(container);
  if (group != null) return group;
  group = {
    container,
    toolbars: new Set(),
    active: null,
    attached: new WeakSet(),
    observer: new MutationObserver(() => {
      group?.refresh();
    }),
    documentObserver: new MutationObserver(() => {
      if (group?.active != null && !isLive(group.active)) {
        group.active = null;
        group.refresh();
      }
    }),
    refresh() {},
  };
  group.refresh = () => {
    if (group == null) return;
    if (group.active != null && !isLive(group.active)) group.active = null;
    Array.from(group.container.querySelectorAll<HTMLElement>('button, select'))
      .forEach((input) => {
        if (group?.attached.has(input)) return;
        group?.attached.add(input);
        if (input.tagName === 'BUTTON') input.setAttribute('type', 'button');
        const eventName = input.tagName === 'SELECT' ? 'change' : 'click';
        input.addEventListener(eventName, (event) => {
          const active = group?.active;
          if (active == null || !isLive(active) || !active.quill.isEnabled()) {
            event.preventDefault();
